				int ii1 = i1+k1 * 1;
				if( ii1<0) continue;
				if( ii1>=16) continue;
				int ii2 = i2+k2 * 1;
				if( ii2<0) continue;
				if( ii2>=32) continue;
				if( curmax < x[b][c][ii0][ii1][ii2]) {
				curmax = MAX( curmax, x[b][c][ii0][ii1][ii2]);
				}
